import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { formatDistanceToNow } from 'date-fns';
import { Monitor, Smartphone, Globe, LogOut, X, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/shadcn/components/ui/button';
import { Badge } from '@/shadcn/components/ui/badge';
import { HarmonyDialog } from '@/components/ui/harmony-dialog';
import { adminService } from '@/api/auth/adminService';
import { getApiErrorMessage } from '@/api/app/apiError';

interface Device {
  id: string;
  deviceName: string | null;
  ipAddress: string | null;
  createdAt: string;
  lastUsedAt: string;
  isRememberMe: boolean;
}

interface UserSessionsModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  userId: string;
  userName: string;
  onRevokedAll?: () => void;
}

const DeviceIcon = ({ name }: { name: string | null }) => {
  const lower = name?.toLowerCase() ?? '';
  if (lower.includes('mobile') || lower.includes('android') || lower.includes('iphone'))
    return <Smartphone size={14} className="text-muted-foreground shrink-0" />;
  if (lower.includes('mozilla') || lower.includes('chrome') || lower.includes('safari'))
    return <Globe size={14} className="text-muted-foreground shrink-0" />;
  return <Monitor size={14} className="text-muted-foreground shrink-0" />;
};

export const UserSessionsModal = ({
  open,
  onOpenChange,
  userId,
  userName,
  onRevokedAll,
}: UserSessionsModalProps) => {
  const queryClient = useQueryClient();
  const devicesKey = ['admin', 'user-devices', userId];

  const { data: devices = [], isLoading } = useQuery<Device[]>({
    queryKey: devicesKey,
    queryFn: () => adminService.getAdminUserDevices(userId),
    enabled: open,
    staleTime: 30_000,
  });

  const revokeOneMutation = useMutation({
    mutationFn: (deviceId: string) => adminService.revokeUserDevice(userId, deviceId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: devicesKey });
      queryClient.invalidateQueries({ queryKey: ['admin', 'security-summary'] });
      toast.success('Session revoked.');
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to revoke session.')),
  });

  const revokeAllMutation = useMutation({
    mutationFn: () => adminService.revokeAllUserDevices(userId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: devicesKey });
      queryClient.invalidateQueries({ queryKey: ['admin', 'security-summary'] });
      toast.success('All sessions revoked.');
      onRevokedAll?.();
      onOpenChange(false);
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to revoke sessions.')),
  });

  const anyPending = revokeOneMutation.isPending || revokeAllMutation.isPending;

  return (
    <HarmonyDialog
      open={open}
      onOpenChange={(o) => { if (!anyPending) onOpenChange(o); }}
      title="Active Sessions"
      description={`Active sessions for ${userName}. You can revoke individual sessions or all at once.`}
      size="md"
      footerChildren={
        devices.length > 0 ? (
          <Button
            variant="destructive"
            size="sm"
            disabled={anyPending}
            onClick={() => revokeAllMutation.mutate()}
          >
            {revokeAllMutation.isPending
              ? <Loader2 size={14} className="mr-1.5 animate-spin" />
              : <LogOut size={14} className="mr-1.5" />
            }
            Revoke All Sessions
          </Button>
        ) : <span />
      }
    >
      {isLoading ? (
        <p className="text-sm text-muted-foreground py-4 text-center">Loading sessions…</p>
      ) : devices.length === 0 ? (
        <p className="text-sm text-muted-foreground py-4 text-center">No active sessions found.</p>
      ) : (
        <ul className="space-y-2">
          {devices.map((d) => (
            <li key={d.id} className="flex items-start gap-3 rounded-md border p-3">
              <DeviceIcon name={d.deviceName} />
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="text-sm font-medium truncate">
                    {d.deviceName ?? 'Unknown device'}
                  </span>
                  {d.isRememberMe && (
                    <Badge variant="outline" className="text-xs">Remember me</Badge>
                  )}
                </div>
                <div className="text-xs text-muted-foreground mt-0.5 space-y-0.5">
                  {d.ipAddress && <div>IP: {d.ipAddress}</div>}
                  <div>Last active: {formatDistanceToNow(new Date(d.lastUsedAt), { addSuffix: true })}</div>
                  <div>Created: {formatDistanceToNow(new Date(d.createdAt), { addSuffix: true })}</div>
                </div>
              </div>
              <Button
                size="icon-xs"
                variant="ghost"
                className="shrink-0 text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                disabled={anyPending}
                onClick={() => revokeOneMutation.mutate(d.id)}
                title="Revoke this session"
              >
                {revokeOneMutation.isPending && revokeOneMutation.variables === d.id
                  ? <Loader2 size={12} className="animate-spin" />
                  : <X size={12} />
                }
              </Button>
            </li>
          ))}
        </ul>
      )}
    </HarmonyDialog>
  );
};
